import React, { useState } from "react";
import { BrowserRouter as Router, Route, Routes } from "react-router-dom"; // Import React Router
import Sidebar from "./components/Sidebar";
import Dashboard from "./components/Dashboard";
import Classrooms from "./components/classsection/Classrooms";
import Events from "./components/Events";
import Detail from "./components/Details";
import Settings from "./components/Settings";
import AddStudent from "./components/AddStudent"; // Import AddStudent
import StudentData from "./components/StudentData"; // New page to display student data
import "./App.css";

function App() {
  const [selectedPage, setSelectedPage] = useState("dashboard");

  return (
    <Router>
      <div className="app-container">
        <Sidebar onSelectPage={setSelectedPage} />
        <div className="main-content">
          <header className="header">
            <div className="header__left">
              <h2>Welcome, Rajeshwaran</h2>
            </div>
            <div className="header__right">
              <span className="material-icons header__icon">notifications</span>
              <span className="material-icons header__icon">account_circle</span>
            </div>
          </header>
          <div className="content">
            <Routes>
              <Route path="/" element={<Dashboard />} />
              <Route path="/classrooms" element={<Classrooms />} />
              <Route path="/events" element={<Events />} />
              <Route path="/details" element={<Detail />} />
              <Route path="/settings" element={<Settings />} />
              <Route path="/add-student" element={<AddStudent />} /> {/* Add the AddStudent route */}
              <Route path="/student-data" element={<StudentData />} /> {/* Add the StudentData route */}
            </Routes>
          </div>
        </div>
      </div>
    </Router>
  );
}

export default App;
